import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const SellerViewOrders = () => {
    const [orders, setOrders] = useState([]);
    const navigate = useNavigate();
    const sellerId = sessionStorage.getItem("sellerid");

    useEffect(() => {
        if (!sellerId) {
            navigate("/seller/signin");
            return;
        }

        axios.post("http://localhost:3001/seller/vieworders", { sellerId })
            .then(response => {
                if (Array.isArray(response.data)) {
                    setOrders(response.data);
                } else {
                    console.log(response.data);
                    setOrders([]);
                }
            })
            .catch(err => {
                console.error("Error fetching orders:", err);
                alert("Could not fetch orders.");
            });
    }, [sellerId, navigate]);

    return (
        <div className="container">
            <h2 className="mt-3">Your Orders</h2>
            <div className="row g-3 mt-3">
                {orders.length > 0 ? orders.map(order => (
                    <div key={order._id} className="ccol col-12 col-sm-12 col-md-12 col-lg-12 col-xl-12 col-xxl-12">
                        <div className="card mb-3">
                            <div className="card-header">
                                <div className="d-flex justify-content-between">
                                    <div><strong>Order ID:</strong> {order._id}</div>
                                    <div><strong>Date:</strong> {new Date(order.orderDate).toLocaleDateString()}</div>
                                </div>
                            </div>
                            <div className="card-body">
                                <h5 className="card-title">Customer: {order.customerId ? order.customerId.name : 'N/A'} ({order.customerId ? order.customerId.email : 'N/A'})</h5>
                                <p className="card-text text-muted"><small>This order contains at least one product sold by you. The total amount shown is for the customer's entire order.</small></p>
                                <table className="table table-sm">
                                    <thead>
                                        <tr>
                                            <th scope="col">Product</th>
                                            <th scope="col">Quantity</th>
                                            <th scope="col">Unit Price</th>
                                            <th scope="col">Subtotal</th>
                                            <th scope="col">Sold by You</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {order.items.map(item => (
                                            <tr key={item._id}>
                                                <td>{item.productId ? item.productId.name : 'Product not found'}</td>
                                                <td>{item.quantity}</td>
                                                <td>${item.productId ? item.productId.price.toFixed(2) : 'N/A'}</td>
                                                <td>${item.productId ? (item.productId.price * item.quantity).toFixed(2) : 'N/A'}</td>
                                                <td><span className={item.productId && item.productId.sellerId === sellerId ? "badge bg-success" : "badge bg-secondary"}>{item.productId && item.productId.sellerId === sellerId ? 'Yes' : 'No'}</span></td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                            <div className="card-footer text-end">
                                <h5>Order Total Amount: ${order.totalAmount.toFixed(2)}</h5>
                            </div>
                        </div>
                    </div>
                )) : <div className="col"><p>No orders containing your products were found.</p></div>}
            </div>
        </div>
    );
};

export default SellerViewOrders;
